[gcode_macro SET_SHUTDOWN_AFTER_PRINT]
variable_shutdown: 0
gcode:
  {% set enable = params.ENABLE|default(1)|int %}
  {% if enable %}
    SET_GCODE_VARIABLE MACRO=SET_SHUTDOWN_AFTER_PRINT VARIABLE=shutdown VALUE=1
    M118 "Shutdown on print complete: ON"
  {% else %}
    SET_GCODE_VARIABLE MACRO=SET_SHUTDOWN_AFTER_PRINT VARIABLE=shutdown VALUE=0
    M118 "Shutdown on print complete: OFF"
  {% endif %}
